// Formatting utilities for session metrics display

import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'

dayjs.extend(relativeTime)

export const formatMs = (ms: number): string => {
  if (ms < 1) return '<1ms'
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(2)}s`
}

export const formatDuration = (ms: number | null): string => {
  if (ms == null) return '—'
  const seconds = Math.floor(ms / 1000)
  const minutes = Math.floor(seconds / 60)
  const hours = Math.floor(minutes / 60)
  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`
  return `${seconds}s`
}

export const formatDate = (iso: string | null): string => {
  if (!iso) return '—'
  return dayjs(iso).format('MMM D, YYYY h:mm A')
}

export const computeAvg = (values: number[]) => {
  if (!values.length) return 0
  return Math.round(values.reduce((a, b) => a + b, 0) / values.length)
}

export const computePercentile = (values: number[], p: number) => {
  if (!values.length) return 0
  const sorted = [...values].sort((a, b) => a - b)
  const idx = Math.min(Math.floor(sorted.length * p), sorted.length - 1)
  return sorted[idx]
}

import type {
  AgentSessionRow,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  PlivoListResponse,
  SessionsFilters,
} from '@/lib/observability-types'

export function createObservabilityApi(baseUrl: string) {
  async function fetchJson<T>(path: string): Promise<T> {
    const res = await fetch(`${baseUrl}${path}`)
    if (!res.ok) throw new Error(`API error: ${res.status} ${res.statusText}`)
    return res.json()
  }

  return {
    listSessions: (limit = 20, offset = 0, filters?: SessionsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      if (filters?.transport && filters.transport.length) {
        params.set('transport', filters.transport.join(','))
      }
      return fetchJson<PlivoListResponse<AgentSessionRow>>(`/sessions?${params}`)
    },

    getSession: (id: string) =>
      fetchJson<AgentSessionRow>(`/sessions/${id}`),

    listEvalRuns: (limit = 20, offset = 0, filters?: EvalsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.agentId) params.set('agent_id', filters.agentId)
      if (filters?.framework && filters.framework.length) {
        params.set('framework', filters.framework.join(','))
      }
      if (filters?.testingFramework && filters.testingFramework.length) {
        params.set('testing_framework', filters.testingFramework.join(','))
      }
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      return fetchJson<PlivoListResponse<EvalRunRow>>(`/evals?${params}`)
    },

    getEvalRun: (runId: string) =>
      fetchJson<EvalRunDetail>(`/evals/${runId}`),

    getEvalCase: (runId: string, caseId: string) =>
      fetchJson<EvalCaseRow & { api_id?: string }>(`/evals/${runId}/cases/${caseId}`),
  }
}

export type ObservabilityApi = ReturnType<typeof createObservabilityApi>

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from 'react'
import { createObservabilityApi, type ObservabilityApi } from '@/lib/observability-api'
import type { AgentSessionRow } from '@/lib/observability-types'

interface ObservabilityContextValue {
  api: ObservabilityApi
  session: AgentSessionRow | null
  sessionLoading: boolean
  sessionError: string | null
  highlightedTurn: number | null
  setHighlightedTurn: (turn: number | null) => void
}

const ObservabilityContext = createContext<ObservabilityContextValue | null>(null)

export function AgentObservabilityProvider({
  baseUrl,
  sessionId,
  children,
}: {
  baseUrl: string
  sessionId?: string
  children: ReactNode
}) {
  const api = useMemo(() => createObservabilityApi(baseUrl), [baseUrl])
  const [session, setSession] = useState<AgentSessionRow | null>(null)
  const [sessionLoading, setSessionLoading] = useState(!!sessionId)
  const [sessionError, setSessionError] = useState<string | null>(null)
  const [highlightedTurn, setHighlightedTurn] = useState<number | null>(null)

  useEffect(() => {
    if (!sessionId) {
      setSession(null)
      setSessionLoading(false)
      return
    }
    setSessionLoading(true)
    setSessionError(null)
    api
      .getSession(sessionId)
      .then(setSession)
      .catch((e) => setSessionError(e.message))
      .finally(() => setSessionLoading(false))
  }, [api, sessionId])

  const value = useMemo<ObservabilityContextValue>(
    () => ({
      api,
      session,
      sessionLoading,
      sessionError,
      highlightedTurn,
      setHighlightedTurn,
    }),
    [api, session, sessionLoading, sessionError, highlightedTurn],
  )

  return (
    <ObservabilityContext.Provider value={value}>
      {children}
    </ObservabilityContext.Provider>
  )
}

export function useObservabilityContext() {
  const ctx = useContext(ObservabilityContext)
  if (!ctx) {
    throw new Error('useObservabilityContext must be used within AgentObservabilityProvider')
  }
  return ctx
}

import { useEffect, useMemo, useState } from 'react'
import { useObservabilityContext } from '@/lib/observability-provider'
import type {
  AgentSessionRow,
  ChatItem,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  MetricsSummary,
  PlivoMeta,
  SessionEvent,
  SessionMetrics,
  SessionsFilters,
  TurnRecord,
} from '@/lib/observability-types'

// ---------------------------------------------------------------------------
// useSessions — fetches paginated session list
// ---------------------------------------------------------------------------

export function useSessions(
  limit = 20,
  offset = 0,
  filters?: SessionsFilters,
) {
  const { api } = useObservabilityContext()
  const [sessions, setSessions] = useState<AgentSessionRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const accountId = filters?.accountId
  const startedFrom = filters?.startedFrom
  const startedTo = filters?.startedTo
  const transport = filters?.transport
  const transportKey = (transport ?? []).slice().sort().join(',')

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listSessions(limit, offset, { accountId, startedFrom, startedTo, transport })
      .then((res) => {
        if (cancelled) return
        setSessions(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => {
        if (!cancelled) setError(e.message)
      })
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, accountId, startedFrom, startedTo, transportKey])

  return { sessions, meta, loading, error }
}

// ---------------------------------------------------------------------------
// useSession — returns the current session from provider context
// ---------------------------------------------------------------------------

export function useSession() {
  const { session, sessionLoading, sessionError } = useObservabilityContext()
  return {
    session,
    loading: sessionLoading,
    error: sessionError,
  }
}

// ---------------------------------------------------------------------------
// useTimeline — derives timeline data from current session
// ---------------------------------------------------------------------------

export function useTimeline() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const recordUrl: string | null = session?.record_url ?? null
  const sessionCreatedAt: string | undefined = session?.created_at

  return { metrics, recordUrl, sessionCreatedAt, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// useTranscript — derives transcript data from current session
// ---------------------------------------------------------------------------

export function useTranscript() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const turns: TurnRecord[] = useMemo(
    () => metrics?.turns ?? [],
    [metrics],
  )
  const chatHistory: ChatItem[] | null = session?.chat_history ?? null

  return { turns, chatHistory, metrics, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// usePerformance — derives performance metrics from current session
// ---------------------------------------------------------------------------

export function usePerformance() {
  const { session } = useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const summary: MetricsSummary | null = metrics?.summary ?? null

  return { metrics, summary }
}

// ---------------------------------------------------------------------------
// useEvents / useOptions — raw session report slices
// ---------------------------------------------------------------------------

export function useEvents(): SessionEvent[] | null {
  const { session } = useObservabilityContext()
  return session?.events ?? null
}

export function useOptions(): Record<string, unknown> | null {
  const { session } = useObservabilityContext()
  return session?.options ?? null
}

// ---------------------------------------------------------------------------
// useEvalRuns / useEvalRun / useEvalCase
// ---------------------------------------------------------------------------

export function useEvalRuns(
  limit = 20,
  initialOffset = 0,
  filters?: EvalsFilters,
) {
  const { api } = useObservabilityContext()
  const [runs, setRuns] = useState<EvalRunRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset: initialOffset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [offset, setOffset] = useState(initialOffset)

  const { agentId, framework, testingFramework, accountId, startedFrom, startedTo } = filters ?? {}
  // Stable string keys for the array filters so effect deps don't churn
  // on new-but-equal-array identities every render.
  const frameworkKey = (framework ?? []).slice().sort().join(',')
  const testingFrameworkKey = (testingFramework ?? []).slice().sort().join(',')

  // Sync offset when the caller passes a live initialOffset (e.g. from URL
  // state). Callers who drive pagination via setOffset pass a stable 0 and
  // this no-ops after mount.
  useEffect(() => {
    setOffset(initialOffset)
  }, [initialOffset])

  useEffect(() => {
    setOffset(0)
  }, [agentId, frameworkKey, testingFrameworkKey, accountId, startedFrom, startedTo])

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listEvalRuns(limit, offset, {
        agentId,
        framework: framework && framework.length ? framework : undefined,
        testingFramework:
          testingFramework && testingFramework.length ? testingFramework : undefined,
        accountId,
        startedFrom,
        startedTo,
      })
      .then((res) => {
        if (cancelled) return
        setRuns(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, agentId, frameworkKey, testingFrameworkKey, accountId, startedFrom, startedTo])

  return { runs, meta, loading, error, offset, setOffset }
}

export function useEvalRun(runId: string | undefined) {
  const { api } = useObservabilityContext()
  const [run, setRun] = useState<EvalRunDetail | null>(null)
  const [loading, setLoading] = useState(!!runId)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!runId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalRun(runId)
      .then((res) => !cancelled && setRun(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId])

  return { run, loading, error }
}

export function useEvalCase(runId: string | undefined, caseId: string | undefined) {
  const { api } = useObservabilityContext()
  const [evalCase, setEvalCase] = useState<EvalCaseRow | null>(null)
  const [loading, setLoading] = useState(!!(runId && caseId))
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!runId || !caseId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalCase(runId, caseId)
      .then((res) => !cancelled && setEvalCase(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId, caseId])

  return { evalCase, loading, error }
}

import { useMemo } from 'react'
import { parseAsArrayOf, parseAsInteger, parseAsString, useQueryState } from 'nuqs'
import type { ColumnDef } from '@tanstack/react-table'
import { Bot, FlaskConical, type LucideIcon } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { DataTableColumnHeader } from '@/components/data-table/data-table-column-header'
import { DataTableToolbar } from '@/components/data-table/data-table-toolbar'
import { ObsDataTable } from '@/components/data-table/obs-data-table'
import { useDataTable } from '@/hooks/use-data-table'
import { cn } from '@/lib/utils'
import { formatDate, formatDuration } from '@/lib/observability-format'
import { useEvalRuns } from '@/lib/observability-hooks'
import type { EvalRunRow } from '@/lib/observability-types'

// Agent framework — what the agent under test is built with.
const FRAMEWORK_OPTIONS = [
  { label: 'LiveKit', value: 'livekit' },
  { label: 'Pipecat', value: 'pipecat' },
]

// Testing framework — what ran the eval suite.
const TESTING_FRAMEWORK_OPTIONS = [
  { label: 'pytest', value: 'pytest' },
  { label: 'Vitest', value: 'vitest' },
]

function PassRateBar({ passed, total }: { passed: number; total: number }) {
  const pct = total > 0 ? Math.round((passed / total) * 100) : 0
  return (
    <div className="flex items-center gap-2 min-w-[120px]">
      <span className="font-mono text-xs-600 tabular-nums w-10">{pct}%</span>
      <div className="flex-1 h-1.5 rounded-full bg-muted overflow-hidden max-w-[90px]">
        <div className="h-full bg-foreground" style={{ width: `${pct}%` }} />
      </div>
    </div>
  )
}

function FrameworkPill({
  name,
  version,
  icon: Icon,
}: {
  name: string | null
  version: string | null
  icon: LucideIcon
}) {
  if (!name) return <span className="text-muted-foreground">—</span>
  return (
    <span className={cn(
      'inline-flex shrink-0 items-center gap-1.5 px-2 py-0.5 rounded-full bg-muted border text-xs-500 whitespace-nowrap',
    )}>
      <Icon className="h-3 w-3 shrink-0 text-muted-foreground" />
      {name}
      {version && <span className="text-muted-foreground font-mono text-[11px]">{version}</span>}
    </span>
  )
}

function FrameworkBadge({ name, version }: { name: string | null; version: string | null }) {
  return <FrameworkPill name={name} version={version} icon={Bot} />
}

function TestingFrameworkBadge({ name, version }: { name: string; version: string | null }) {
  return <FrameworkPill name={name} version={version} icon={FlaskConical} />
}

export const EvalsPage = ({ onRunClick }: { onRunClick?: (runId: string) => void }) => {
  // URL-synced filter state — written by the DataTable toolbar via `useDataTable`.
  // Column ids below (`agent_id`, `account_id`, `framework`, `started_at`) become the URL keys.
  const [page] = useQueryState('page', parseAsInteger.withDefault(1))
  const [perPage] = useQueryState('perPage', parseAsInteger.withDefault(10))
  const [agentId] = useQueryState('agent_id', parseAsString.withDefault(''))
  const [accountId] = useQueryState('account_id', parseAsString.withDefault(''))
  const [framework] = useQueryState(
    'framework',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  const [testingFramework] = useQueryState(
    'testing_framework',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  // Single-date filter emits the picked day's midnight (local) as an epoch-ms
  // string. Expanded server-side into a 00:00 → next-midnight window.
  const [startedAt] = useQueryState(
    'started_at',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  const startedDay = useMemo(() => {
    const v = startedAt[0]
    if (!v) return undefined
    const d = new Date(Number(v))
    return Number.isNaN(d.getTime()) ? undefined : d
  }, [startedAt])
  const startedFromIso = useMemo(() => startedDay?.toISOString(), [startedDay])
  const startedToIso = useMemo(() => {
    if (!startedDay) return undefined
    const end = new Date(startedDay)
    end.setHours(23, 59, 59, 999)
    return end.toISOString()
  }, [startedDay])

  const { runs, meta, loading, error } = useEvalRuns(
    Math.min(perPage, 20),
    (page - 1) * Math.min(perPage, 20),
    {
      agentId: agentId || undefined,
      accountId: accountId || undefined,
      framework: framework.length ? framework : undefined,
      testingFramework: testingFramework.length ? testingFramework : undefined,
      startedFrom: startedFromIso,
      startedTo: startedToIso,
    },
  )

  const columns = useMemo<ColumnDef<EvalRunRow>[]>(
    () => [
      {
        id: 'run_id',
        accessorKey: 'run_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Run" />,
        cell: ({ row }) => <span className="mono">{row.original.run_id.slice(0, 8)}</span>,
        enableSorting: false,
        meta: { label: 'Run' },
      },
      {
        id: 'agent_id',
        accessorKey: 'agent_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Agent" />,
        cell: ({ row }) =>
          row.original.agent_id ? (
            <span style={{ font: 'var(--text-p-500)' }}>{row.original.agent_id}</span>
          ) : (
            <span className="muted">—</span>
          ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: { label: 'Agent', placeholder: 'Filter by agent', variant: 'text' },
      },
      {
        id: 'framework',
        accessorKey: 'framework',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Framework" />,
        cell: ({ row }) => (
          <FrameworkBadge
            name={row.original.framework}
            version={row.original.framework_version}
          />
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: {
          label: 'Framework',
          variant: 'multiSelect',
          options: FRAMEWORK_OPTIONS,
        },
      },
      {
        id: 'testing_framework',
        accessorKey: 'testing_framework',
        header: ({ column }) => (
          <DataTableColumnHeader column={column} label="Testing Framework" />
        ),
        cell: ({ row }) => (
          <TestingFrameworkBadge
            name={row.original.testing_framework}
            version={row.original.testing_framework_version}
          />
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: {
          label: 'Testing Framework',
          variant: 'multiSelect',
          options: TESTING_FRAMEWORK_OPTIONS,
        },
      },
      {
        id: 'account_id',
        accessorKey: 'account_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Account" />,
        cell: ({ row }) =>
          row.original.account_id ? (
            <span className="muted" style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>
              {row.original.account_id}
            </span>
          ) : (
            <span className="muted">—</span>
          ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: { label: 'Account', placeholder: 'Filter by account', variant: 'text' },
      },
      {
        id: 'pass_rate',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Pass rate" />,
        cell: ({ row }) => {
          const r = row.original
          const failed = r.failed + r.errored
          return (
            <div className="flex items-center gap-2">
              <PassRateBar passed={r.passed} total={r.total} />
              {failed > 0 && (
                <Badge variant="outline" className="text-xxs-600 uppercase tracking-wider">
                  {failed} fail
                </Badge>
              )}
            </div>
          )
        },
        enableSorting: false,
      },
      {
        id: 'total',
        accessorKey: 'total',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Cases" />,
        cell: ({ row }) => <span className="tnum">{row.original.total}</span>,
        enableSorting: false,
        meta: { label: 'Cases' },
      },
      {
        id: 'duration_ms',
        accessorKey: 'duration_ms',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Duration" />,
        cell: ({ row }) => (
          <span className="mono tnum">{formatDuration(row.original.duration_ms)}</span>
        ),
        enableSorting: false,
        meta: { label: 'Duration' },
      },
      {
        id: 'started_at',
        accessorKey: 'started_at',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Started" />,
        cell: ({ row }) => (
          <span className="tnum" style={{ color: 'hsl(var(--secondary))' }}>
            {formatDate(row.original.started_at)}
          </span>
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: { label: 'Started', variant: 'date' },
      },
      {
        id: 'commit',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Commit" />,
        cell: ({ row }) => (
          <span className="muted" style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>
            {row.original.ci?.git_sha ? String(row.original.ci.git_sha).slice(0, 7) : '—'}
          </span>
        ),
        enableSorting: false,
      },
    ],
    [],
  )

  const totalCount = meta.total_count
  const pageCount = Math.max(1, Math.ceil(totalCount / perPage))

  const { table } = useDataTable({
    data: runs,
    columns,
    pageCount,
    initialState: { pagination: { pageIndex: 0, pageSize: 10 } },
    getRowId: (row) => row.run_id,
  })

  return (
    <div className="w-full p-6 flex flex-col gap-4 min-w-0">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-h2-600 font-semibold m-0">Evals</h1>
          <div className="text-s-400 text-muted-foreground">Test runs across your agents.</div>
        </div>
        <div className="text-s-400 text-muted-foreground">
          <b className="text-foreground">{totalCount}</b> total
        </div>
      </div>

      {error && (
        <div
          role="alert"
          className="border border-border bg-muted text-foreground px-4 py-2.5 rounded-lg text-s-400"
        >
          Failed to load eval runs: {error}
        </div>
      )}

      <ObsDataTable
        table={table}
        toolbar={<DataTableToolbar table={table} />}
        onRowClick={(row) => onRunClick?.(row.original.run_id)}
        totalRowCount={totalCount}
        loading={loading}
      />
    </div>
  )
}
